import { describe, it, expect, beforeEach } from 'vitest';
import fc from 'fast-check';
import { chainFinalityHandler } from '../../handlers/ts/app/governance/chain-finality.handler.js';
import {
  classifyPurity,
  extractCompletionVariants,
  extractReadSet,
  extractWriteSet,
  extractPerformSet,
} from '../../runtime/storage-program.js';
import { interpret } from '../../runtime/interpreter.js';
import { createInMemoryStorage } from '../../runtime/adapters/storage.js';

describe('ChainFinality functional handler', () => {
  let storage: ReturnType<typeof createInMemoryStorage>;

  beforeEach(() => {
    storage = createInMemoryStorage();
  });

  describe('track', () => {
    it('builds a valid StorageProgram', () => {
      const program = chainFinalityHandler.track({ operationRef: 'test-operationRef', txHash: 'test-txHash', chainId: 'test-chainId', requiredConfirmations: 1 });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = chainFinalityHandler.track({ operationRef: 'test-operationRef', txHash: 'test-txHash', chainId: 'test-chainId', requiredConfirmations: 1 });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('covers all declared variants', () => {
      const program = chainFinalityHandler.track({ operationRef: 'test-operationRef', txHash: 'test-txHash', chainId: 'test-chainId', requiredConfirmations: 1 });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = extractCompletionVariants(program);
      expect(variants).toContain('tracking');
    });

    it('declares read and write sets', () => {
      const program = chainFinalityHandler.track({ operationRef: 'test-operationRef', txHash: 'test-txHash', chainId: 'test-chainId', requiredConfirmations: 1 });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = chainFinalityHandler.track({ operationRef: 'test-operationRef', txHash: 'test-txHash', chainId: 'test-chainId', requiredConfirmations: 1 });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('executes successfully', async () => {
      if (typeof chainFinalityHandler.track !== 'function') return;
      const result = await interpret(chainFinalityHandler.track({ operationRef: 'test-operationRef', txHash: 'test-txHash', chainId: 'test-chainId', requiredConfirmations: 1 }), storage);
      expect(result).toBeDefined();
      expect(result.variant).toBeDefined();
      expect(typeof result.variant).toBe('string');
    });

  });

  describe('checkFinality', () => {
    it('builds a valid StorageProgram', () => {
      const program = chainFinalityHandler.checkFinality({ entry: 'test' });
      expect(program).toBeDefined();
      expect(program.instructions).toBeDefined();
      expect(Array.isArray(program.instructions)).toBe(true);
      expect(program.instructions.length).toBeGreaterThan(0);
    });

    it('has classifiable purity', () => {
      const program = chainFinalityHandler.checkFinality({ entry: 'test' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const purity = classifyPurity(program);
      expect(['pure', 'read-only', 'read-write']).toContain(purity);
    });

    it('covers all declared variants', () => {
      const program = chainFinalityHandler.checkFinality({ entry: 'test' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const variants = extractCompletionVariants(program);
      expect(variants).toContain('pending');
      expect(variants).toContain('finalized');
      expect(variants).toContain('reorged');
    });

    it('declares read and write sets', () => {
      const program = chainFinalityHandler.checkFinality({ entry: 'test' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const reads = extractReadSet(program);
      const writes = extractWriteSet(program);
      const purity = classifyPurity(program);
      if (purity === 'read-only') {
        expect(reads.size).toBeGreaterThan(0);
      } else if (purity === 'read-write') {
        expect(writes.size).toBeGreaterThan(0);
      }
    });

    it('has trackable transport effects', () => {
      const program = chainFinalityHandler.checkFinality({ entry: 'test' });
      if (!program?.instructions) return; // skip non-StorageProgram handlers
      const effects = extractPerformSet(program);
      expect(effects).toBeDefined();
    });

    it('executes successfully', async () => {
      if (typeof chainFinalityHandler.checkFinality !== 'function') return;
      const result = await interpret(chainFinalityHandler.checkFinality({ entry: 'test' }), storage);
      expect(result).toBeDefined();
      expect(result.variant).toBeDefined();
      expect(typeof result.variant).toBe('string');
    });

  });

  describe('invariant examples', () => {
    it("track-then-checkFinality", async () => {
      const storage = createInMemoryStorage();
      const trackResult0 = await interpret(chainFinalityHandler.track({ operationRef: {"type":"variable","name":"_"}, txHash: {"type":"variable","name":"_"}, chainId: {"type":"variable","name":"_"}, requiredConfirmations: {"type":"literal","value":12} }), storage);
      expect(trackResult0.variant).toBe("tracking");
      const entry = trackResult0.output["entry"];
      const thenResult0 = await interpret(chainFinalityHandler.checkFinality({ entry: {"type":"variable","name":"cf"} }), storage);
      expect(thenResult0.variant).toBe("finalized");
    });

  });

  describe('state invariants (stateful PBT)', () => {
    it('always: valid-operationRef', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('track'), input: fc.record({ operationRef: fc.string({ minLength: 1, maxLength: 20 }), txHash: fc.string({ minLength: 1, maxLength: 20 }), chainId: fc.string({ minLength: 1, maxLength: 20 }), requiredConfirmations: fc.integer({ min: 0, max: 1000 }) }) }),
              fc.record({ action: fc.constant('checkFinality'), input: fc.record({ entry: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = chainFinalityHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(chainFinalityHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('never: orphaned-txHash', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('track'), input: fc.record({ operationRef: fc.string({ minLength: 1, maxLength: 20 }), txHash: fc.string({ minLength: 1, maxLength: 20 }), chainId: fc.string({ minLength: 1, maxLength: 20 }), requiredConfirmations: fc.integer({ min: 0, max: 1000 }) }) }),
              fc.record({ action: fc.constant('checkFinality'), input: fc.record({ entry: fc.string() }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = chainFinalityHandler[step.action];
              if (typeof actionFn === 'function') {
                const program = actionFn.call(chainFinalityHandler, step.input as Record<string, unknown>);
                const result = await interpret(program, storage);
                expect(result.variant).toBeDefined();
                // Never: orphaned-txHash
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

  describe('action contracts (PBT)', () => {
    it('track requires: ', async () => {
      const storage = createInMemoryStorage();
      const result = await interpret(chainFinalityHandler.track({  }), storage);
      expect(['error', 'invalid', 'missing', 'notFound']).toContain(result.variant);
    });

    it('track ensures on tracking: ', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.record({ operationRef: fc.string({ minLength: 1, maxLength: 50 }), txHash: fc.string({ minLength: 1, maxLength: 50 }), chainId: fc.string({ minLength: 1, maxLength: 50 }), requiredConfirmations: fc.integer({ min: 1, max: 1000 }) }),
          async (input) => {
            const storage = createInMemoryStorage();
            const program = chainFinalityHandler.track(input as Record<string, unknown>);
            const result = await interpret(program, storage);
            fc.pre(result.variant === "tracking");
            expect(result.output).toBeDefined();
          },
        ),
        { numRuns: 100 },
      );
    });

  });

});
